const { ApolloServer, gql } = require('apollo-server');
const { invoices } = require('./data'); // Assuming invoices is an array of invoice objects

// Define the GraphQL schema
const typeDefs = gql`
  type Invoice {
    id: ID!
    amount: Float!
    date: String!
    customerName: String!
  }

  type Query {
    getInvoiceById(id: ID!): Invoice
  }
`;

// Implement the resolvers
const resolvers = {
  Query: {
    getInvoiceById: (parent, args, context, info) => {
      const { id } = args;
      // Ensure the ID is a valid number to prevent injection attacks
      if (!/^\d+$/.test(id)) {
        throw new Error('Invalid invoice ID format');
      }
      // Find the invoice by ID
      const invoice = invoices.find(invoice => invoice.id === id);
      if (!invoice) {
        throw new Error('Invoice not found');
      }
      return invoice;
    }
  }
};

// Create the Apollo Server instance
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Assume authentication middleware has already set req.user
    if (!req.user) {
      throw new Error('Unauthorized');
    }
    return { user: req.user };
  }
});

// Start the server
server.listen().then(({ url }) => {
  console.log(`Server ready at ${url}`);
});